export class MiniMap {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private container: HTMLDivElement;
  private scale = 2; // pixels per block

  constructor() {
    this.container = document.createElement('div');
    this.container.id = 'minimap';
    this.container.style.cssText = `
      position: absolute;
      bottom: 80px;
      right: 20px;
      background: rgba(0,0,0,0.8);
      border: 2px solid #333;
      border-radius: 4px;
      z-index: 55;
      pointer-events: none;
    `;

    this.canvas = document.createElement('canvas');
    this.canvas.style.display = 'block';
    this.container.appendChild(this.canvas);

    this.ctx = this.canvas.getContext('2d')!;
    document.body.appendChild(this.container);
  }

  update(
    blocks: { surfaceType: number; texture: number }[][],
    units: { x: number; y: number; selected: boolean }[],
    buildings: { bx: number; by: number; type: string }[],
    cameraX: number,
    cameraZ: number
  ): void {
    const height = blocks.length;
    const width = height > 0 ? blocks[0].length : 0;

    this.canvas.width = width * this.scale;
    this.canvas.height = height * this.scale;
    this.container.style.width = `${this.canvas.width}px`;
    this.container.style.height = `${this.canvas.height}px`;

    // Draw terrain
    for (let by = 0; by < height; by++) {
      for (let bx = 0; bx < width; bx++) {
        const block = blocks[by][bx];
        let color = '#8B7355'; // Default floor

        if (block.surfaceType >= 1 && block.surfaceType <= 5) {
          color = '#5C4033'; // Walls
        } else if (block.surfaceType === 0x20) {
          color = '#00FF88'; // Crystal
        } else if (block.surfaceType === 0x40) {
          color = '#FF8800'; // Ore
        } else if (block.surfaceType === 0x70) {
          color = '#FF3300'; // Lava
        } else if (block.texture === 0x60) {
          color = '#4488FF'; // Power path
        }

        this.ctx.fillStyle = color;
        this.ctx.fillRect(bx * this.scale, by * this.scale, this.scale, this.scale);
      }
    }

    // Draw buildings
    for (const b of buildings) {
      const colors: Record<string, string> = {
        tool_store: '#FF6B00',
        teleport_pad: '#4488FF',
        power_station: '#FF4444',
        support_station: '#44FF44',
        geodome: '#44FFFF',
        refinery: '#FFAA00',
        super_teleport: '#FF00FF'
      };
      this.ctx.fillStyle = colors[b.type] || '#888';
      this.ctx.fillRect(
        (b.bx - 0.5) * this.scale,
        (b.by - 0.5) * this.scale,
        this.scale * 2,
        this.scale * 2
      );
    }

    // Draw units
    for (const u of units) {
      this.ctx.fillStyle = u.selected ? '#00FF00' : '#FFFF00';
      this.ctx.beginPath();
      this.ctx.arc(
        u.x * this.scale,
        u.y * this.scale,
        this.scale * 1.5,
        0,
        Math.PI * 2
      );
      this.ctx.fill();
    }

    // Draw camera viewport indicator
    this.ctx.strokeStyle = '#FFFFFF';
    this.ctx.lineWidth = 1;
    const viewSize = 20;
    const camBX = Math.round((cameraX + (width * 40) / 2) / 40);
    const camBY = Math.round((cameraZ + (height * 40) / 2) / 40);
    this.ctx.strokeRect(
      (camBX - viewSize / 2) * this.scale,
      (camBY - viewSize / 2) * this.scale,
      viewSize * this.scale,
      viewSize * this.scale
    );
  }

  dispose(): void {
    this.container.remove();
  }
}
