import * as THREE from 'three';

export class ParticleSystem {
  private scene: THREE.Scene;
  private particles: {
    mesh: THREE.Mesh;
    velocity: THREE.Vector3;
    life: number;
    maxLife: number;
  }[] = [];
  private geometry = new THREE.BoxGeometry(1, 1, 1);

  constructor(scene: THREE.Scene) {
    this.scene = scene;
  }

  spawnDrillParticles(x: number, y: number, z: number, count: number = 5): void {
    for (let i = 0; i < count; i++) {
      const material = new THREE.MeshBasicMaterial({
        color: new THREE.Color().setHSL(0.08 + Math.random() * 0.05, 0.8, 0.5),
        transparent: true,
        opacity: 0.8
      });
      const mesh = new THREE.Mesh(this.geometry, material);
      mesh.position.set(
        x + (Math.random() - 0.5) * 4,
        y + (Math.random() - 0.5) * 4,
        z + (Math.random() - 0.5) * 4
      );
      mesh.scale.setScalar(0.5 + Math.random() * 1);
      this.scene.add(mesh);

      this.particles.push({
        mesh,
        velocity: new THREE.Vector3(
          (Math.random() - 0.5) * 10,
          Math.random() * 15 + 5,
          (Math.random() - 0.5) * 10
        ),
        life: 1.0,
        maxLife: 1.0
      });
    }
  }

  spawnCrystalCollectParticles(x: number, y: number, z: number): void {
    for (let i = 0; i < 10; i++) {
      const material = new THREE.MeshBasicMaterial({
        color: new THREE.Color().setHSL(0.45 + Math.random() * 0.1, 1, 0.6),
        transparent: true,
        opacity: 0.9
      });
      const mesh = new THREE.Mesh(this.geometry, material);
      mesh.position.set(x, y, z);
      mesh.scale.setScalar(0.3 + Math.random() * 0.5);
      this.scene.add(mesh);

      this.particles.push({
        mesh,
        velocity: new THREE.Vector3(
          (Math.random() - 0.5) * 20,
          Math.random() * 20 + 10,
          (Math.random() - 0.5) * 20
        ),
        life: 1.5,
        maxLife: 1.5
      });
    }
  }

  spawnOreCollectParticles(x: number, y: number, z: number): void {
    for (let i = 0; i < 8; i++) {
      const material = new THREE.MeshBasicMaterial({
        color: new THREE.Color().setHSL(0.08, 0.9, 0.5),
        transparent: true,
        opacity: 0.9
      });
      const mesh = new THREE.Mesh(this.geometry, material);
      mesh.position.set(x, y, z);
      mesh.scale.setScalar(0.3 + Math.random() * 0.5);
      this.scene.add(mesh);

      this.particles.push({
        mesh,
        velocity: new THREE.Vector3(
          (Math.random() - 0.5) * 15,
          Math.random() * 15 + 5,
          (Math.random() - 0.5) * 15
        ),
        life: 1.2,
        maxLife: 1.2
      });
    }
  }

  update(deltaTime: number): void {
    for (let i = this.particles.length - 1; i >= 0; i--) {
      const p = this.particles[i];
      p.life -= deltaTime;

      if (p.life <= 0) {
        this.scene.remove(p.mesh);
        p.mesh.geometry.dispose();
        (p.mesh.material as THREE.Material).dispose();
        this.particles.splice(i, 1);
        continue;
      }

      // Update position
      p.mesh.position.add(p.velocity.clone().multiplyScalar(deltaTime));
      // Gravity
      p.velocity.y -= 20 * deltaTime;
      // Fade out
      const alpha = p.life / p.maxLife;
      (p.mesh.material as THREE.MeshBasicMaterial).opacity = alpha;
      // Shrink
      p.mesh.scale.setScalar(alpha * 1.5);
    }
  }

  dispose(): void {
    for (const p of this.particles) {
      this.scene.remove(p.mesh);
      p.mesh.geometry.dispose();
      (p.mesh.material as THREE.Material).dispose();
    }
    this.particles = [];
  }
}
